// Barrel for the BTDrawer organism.

export 'drawer.types.dart';
export 'drawer.widget.dart';
export 'internal/drawer_draggable.dart';

/// BTDrawer — bottom-sheet drawer panel with drag handle, header, body, footer.
///
/// Figma source: M-Drawer node 2930:20802 (mobile).
///
/// ## Usage:
/// ```dart
/// // Standard — two-button footer:
/// BTDrawer(
///   title: 'Move Goal',
///   subtext: 'Set your daily move goal.',
///   content: Text('Body content'),
///   onPrimary: () {},
///   onSecondary: () {},
/// )
///
/// // Custom footer (e.g. calendar footer with date text + presets):
/// BTDrawer(
///   title: 'Pilih Tanggal',
///   content: BTCalendar(showFooter: false),
///   footer: BTCalendarFooter(
///     selectedRange: _range,
///     onApply: () {},
///     onCancel: () {},
///   ),
/// )
///
/// // No header (title/subtext/close all absent — zero space):
/// BTDrawer(
///   hasCloseIcon: false,
///   content: Text('Content only'),
///   onPrimary: () {},
/// )
///
/// // As a modal bottom sheet:
/// await BTDrawer.show(
///   context,
///   title: 'Settings',
///   content: Text('Body content'),
///   onPrimary: () => Navigator.pop(context),
///   onSecondary: () => Navigator.pop(context),
/// );
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import 'package:flutter/material.dart';

class BTDrawer extends StatelessWidget {
  const BTDrawer({
    this.title,
    this.subtext,
    this.hasCloseIcon = true,
    this.hasFooter = true,
    this.primaryLabel = 'Confirm',
    this.hasSecondaryButton = true,
    this.secondaryLabel = 'Cancel',
    this.content,
    this.footer,
    this.onPrimary,
    this.onSecondary,
    this.onClose,
    super.key,
  });

  /// Bold title shown at the top of the header.
  final String? title;

  /// Optional supporting text below the title.
  final String? subtext;

  /// Show the X close button in the header.
  final bool hasCloseIcon;

  /// Show the default two-button footer. Ignored when [footer] is provided.
  final bool hasFooter;

  /// Label for the primary (top) action button.
  final String primaryLabel;

  /// Show the secondary button below the primary.
  final bool hasSecondaryButton;

  /// Label for the secondary button.
  final String secondaryLabel;

  /// Widget rendered in the flexible body area.
  final Widget? content;

  /// Custom footer widget. When provided, overrides [hasFooter]/[onPrimary]/
  /// [onSecondary] — use this for complex footers (e.g. calendar with date
  /// text + presets above the action buttons).
  final Widget? footer;

  /// Called when the primary action button is pressed.
  final VoidCallback? onPrimary;

  /// Called when the secondary action button is pressed.
  final VoidCallback? onSecondary;

  /// Called when the X close button is pressed.
  final VoidCallback? onClose;

  /// Show a [BTDrawer] as a modal bottom sheet with a scrim barrier.
  ///
  /// Returns whatever the caller passes to `Navigator.pop(context, ...)` from
  /// inside [onPrimary] / [onSecondary] / [onClose] / [footer].
  static Future<T?> show<T>(
    BuildContext context, {
    String? title,
    String? subtext,
    bool hasCloseIcon = true,
    bool hasFooter = true,
    String primaryLabel = 'Confirm',
    bool hasSecondaryButton = true,
    String secondaryLabel = 'Cancel',
    bool isDismissible = true,
    Widget? content,
    Widget? footer,
    VoidCallback? onPrimary,
    VoidCallback? onSecondary,
    VoidCallback? onClose,
  }) {
    return showModalBottomSheet<T>(
      context: context,
      isDismissible: isDismissible,
      enableDrag: true,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      barrierColor: Colors.black54,
      builder: (ctx) => BTDrawer(
        title: title,
        subtext: subtext,
        hasCloseIcon: hasCloseIcon,
        hasFooter: hasFooter,
        primaryLabel: primaryLabel,
        hasSecondaryButton: hasSecondaryButton,
        secondaryLabel: secondaryLabel,
        content: content,
        footer: footer,
        onPrimary: onPrimary ?? () => Navigator.of(ctx).pop(),
        onSecondary: onSecondary ?? () => Navigator.of(ctx).pop(),
        onClose: onClose ?? () => Navigator.of(ctx).pop(),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final radius = context.btRadius;
    final hasHeader = title != null || subtext != null || hasCloseIcon;

    return Material(
      color: Colors.transparent,
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Floating drag handle (above the white panel) ─────────────────
          Container(
            height: 20.0,
            alignment: Alignment.center,
            child: Container(
              width: 60.0,
              height: 4.0,
              decoration: BoxDecoration(
                color: colors.bg.subtlest,
                borderRadius: BorderRadius.circular(radius.rd),
              ),
            ),
          ),

          // ── White drawer panel ────────────────────────────────────────────
          Container(
            width: double.infinity,
            decoration: BoxDecoration(
              color: colors.bg.primary,
              borderRadius: BorderRadius.only(
                topLeft: Radius.circular(radius.xl),
                topRight: Radius.circular(radius.xl),
              ),
              boxShadow: const [
                BoxShadow(
                  color: Color(0x26000000),
                  blurRadius: 24,
                  offset: Offset(0, -4),
                ),
              ],
            ),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                // ── Header — only rendered when at least one element present ──
                if (hasHeader)
                  Padding(
                    padding: EdgeInsets.fromLTRB(16.0, 24.0, 16.0, 16.0),
                    child: Row(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Expanded(
                          child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              if (title != null)
                                Text(
                                  title!,
                                  style: TextStyle(
                                    fontFamily: BTTypography.fontFamily,
                                    fontSize: 18.0,
                                    fontWeight: FontWeight.w700,
                                    height: 1.4,
                                    color: colors.text.primary,
                                  ),
                                ),
                              if (subtext != null) ...[
                                SizedBox(height: 4.0),
                                Text(
                                  subtext!,
                                  style: TextStyle(
                                    fontFamily: BTTypography.fontFamily,
                                    fontSize: 14.0,
                                    fontWeight: FontWeight.w500,
                                    height: 1.4,
                                    color: colors.text.secondary,
                                  ),
                                ),
                              ],
                            ],
                          ),
                        ),
                        if (hasCloseIcon)
                          GestureDetector(
                            onTap: onClose,
                            behavior: HitTestBehavior.opaque,
                            child: SizedBox(
                              width: 24.0,
                              height: 24.0,
                              child: Icon(
                                Icons.close,
                                size: 16,
                                color: colors.text.secondary,
                              ),
                            ),
                          ),
                      ],
                    ),
                  ),

                // ── Body (flexible content area) ─────────────────────────────
                if (content != null)
                  Flexible(
                    child: SingleChildScrollView(
                      padding: EdgeInsets.fromLTRB(16.0, 16.0, 16.0, 0),
                      child: content,
                    ),
                  ),

                // ── Footer — custom widget takes priority over default buttons ─
                if (footer != null)
                  Padding(
                    padding: EdgeInsets.fromLTRB(16.0, 16.0, 16.0, 48.0),
                    child: footer,
                  )
                else if (hasFooter)
                  Padding(
                    padding: EdgeInsets.fromLTRB(16.0, 16.0, 16.0, 48.0),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.stretch,
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        SizedBox(
                          width: double.infinity,
                          child: BTButton(
                            label: primaryLabel,
                            onPressed: onPrimary,
                          ),
                        ),
                        if (hasSecondaryButton) ...[
                          SizedBox(height: 8.0),
                          SizedBox(
                            width: double.infinity,
                            child: BTButton(
                              label: secondaryLabel,
                              variant: BTButtonVariant.secondaryLight,
                              onPressed: onSecondary,
                            ),
                          ),
                        ],
                      ],
                    ),
                  ),
              ],
            ),
          ),
        ],
      ),
    );
  }
}

/// BTDrawerDraggable — draggable scrollable bottom sheet.
///
/// Uses [DraggableScrollableSheet] so the sheet height is driven by user drag
/// gestures. The drag handle, header, and footer stay fixed outside the scroll
/// area; only the body scrolls. Snap positions can be customised.
///
/// ## Usage:
/// ```dart
/// // Standard — two-button footer:
/// await BTDrawerDraggable.show<bool>(
///   context,
///   title: 'Choose items',
///   initialSize: 0.5,
///   maxSize: 0.9,
///   contentBuilder: (ctx, sc, _) => ListView.builder(
///     controller: sc,
///     itemCount: 20,
///     itemBuilder: (_, i) => ListTile(title: Text('Item $i')),
///   ),
///   onPrimary: () => Navigator.pop(context, true),
/// );
///
/// // Custom footer (e.g. calendar footer with date text):
/// await BTDrawerDraggable.show(
///   context,
///   title: 'Pilih Tanggal',
///   content: BTCalendar(showFooter: false),
///   footer: BTCalendarFooter(
///     selectedRange: _range,
///     onApply: () {},
///     onCancel: () {},
///   ),
/// );
///
/// // Simple content (auto-wrapped in SingleChildScrollView):
/// await BTDrawerDraggable.show(
///   context,
///   title: 'Details',
///   content: Text('Long text…'),
/// );
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../../button/button.types.dart';
import '../../button/button.widget.dart';
import 'package:flutter/material.dart';

abstract final class BTDrawerDraggable {
  /// Show a draggable scrollable bottom sheet.
  ///
  /// [initialSize], [minSize], [maxSize] are fractions of the screen height
  /// (0.0–1.0). The sheet snaps to [snapSizes] plus [minSize] and [maxSize].
  ///
  /// Provide [contentBuilder] when you control the scrollable widget yourself
  /// (e.g. a [ListView] — wire the supplied [ScrollController] to it).
  /// The third argument is a [DraggableScrollableController] you can use to
  /// programmatically resize the sheet (e.g. shrink when switching sub-views).
  /// Provide [content] for simple bodies — it is auto-wrapped in a
  /// [SingleChildScrollView] with the correct controller.
  ///
  /// [footer] overrides [hasFooter]/[onPrimary]/[onSecondary] when provided.
  static Future<T?> show<T>(
    BuildContext context, {
    String? title,
    String? subtext,
    bool hasCloseIcon = true,
    bool hasFooter = true,
    String primaryLabel = 'Confirm',
    bool hasSecondaryButton = true,
    String secondaryLabel = 'Cancel',
    bool isDismissible = true,
    double initialSize = 0.5,
    double minSize = 0.25,
    double maxSize = 0.9,
    List<double>? snapSizes,
    Widget Function(
      BuildContext context,
      ScrollController scrollController,
      DraggableScrollableController sheetController,
    )? contentBuilder,
    Widget? content,
    Widget? footer,
    VoidCallback? onPrimary,
    VoidCallback? onSecondary,
    VoidCallback? onClose,
  }) {
    return showModalBottomSheet<T>(
      context: context,
      isDismissible: isDismissible,
      enableDrag: false,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      barrierColor: Colors.black54,
      builder: (ctx) => _BTDraggableSheetBody(
        hasCloseIcon: hasCloseIcon,
        hasFooter: hasFooter,
        primaryLabel: primaryLabel,
        hasSecondaryButton: hasSecondaryButton,
        secondaryLabel: secondaryLabel,
        isDismissible: isDismissible,
        initialSize: initialSize,
        minSize: minSize,
        maxSize: maxSize,
        title: title,
        subtext: subtext,
        snapSizes: snapSizes,
        contentBuilder: contentBuilder,
        content: content,
        footer: footer,
        onPrimary: onPrimary,
        onSecondary: onSecondary,
        onClose: onClose,
      ),
    );
  }
}

// ── Private sheet body widget ────────────────────────────────────────────────

class _BTDraggableSheetBody extends StatefulWidget {
  const _BTDraggableSheetBody({
    required this.hasCloseIcon,
    required this.hasFooter,
    required this.primaryLabel,
    required this.hasSecondaryButton,
    required this.secondaryLabel,
    required this.isDismissible,
    required this.initialSize,
    required this.minSize,
    required this.maxSize,
    this.title,
    this.subtext,
    this.snapSizes,
    this.contentBuilder,
    this.content,
    this.footer,
    this.onPrimary,
    this.onSecondary,
    this.onClose,
  });

  final String? title;
  final String? subtext;
  final bool hasCloseIcon;
  final bool hasFooter;
  final String primaryLabel;
  final bool hasSecondaryButton;
  final String secondaryLabel;
  final bool isDismissible;
  final double initialSize;
  final double minSize;
  final double maxSize;
  final List<double>? snapSizes;
  final Widget Function(
    BuildContext,
    ScrollController,
    DraggableScrollableController,
  )? contentBuilder;
  final Widget? content;
  final Widget? footer;
  final VoidCallback? onPrimary;
  final VoidCallback? onSecondary;
  final VoidCallback? onClose;

  @override
  State<_BTDraggableSheetBody> createState() => _BTDraggableSheetBodyState();
}

class _BTDraggableSheetBodyState extends State<_BTDraggableSheetBody> {
  late final DraggableScrollableController _dssCtrl;

  @override
  void initState() {
    super.initState();
    _dssCtrl = DraggableScrollableController();
  }

  @override
  void dispose() {
    _dssCtrl.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final radius = context.btRadius;
    final hasHeader =
        widget.title != null || widget.subtext != null || widget.hasCloseIcon;

    // Include initialSize as an intermediate snap point when between min/max.
    final effectiveSnaps = widget.snapSizes ??
        (widget.initialSize > widget.minSize &&
                widget.initialSize < widget.maxSize
            ? [widget.initialSize]
            : null);

    return DraggableScrollableSheet(
      controller: _dssCtrl,
      expand: false,
      initialChildSize: widget.initialSize,
      minChildSize: widget.minSize,
      maxChildSize: widget.maxSize,
      snap: true,
      snapSizes: effectiveSnaps,
      snapAnimationDuration: const Duration(milliseconds: 200),
      shouldCloseOnMinExtent: widget.isDismissible,
      builder: (ctx, scrollController) => Material(
        color: Colors.transparent,
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // ── Floating drag handle (above the white panel) ─────────────
            GestureDetector(
              behavior: HitTestBehavior.translucent,
              onVerticalDragUpdate: (details) {
                if (!_dssCtrl.isAttached) return;
                final screenH = MediaQuery.of(ctx).size.height;
                final newSize =
                    (_dssCtrl.size - details.delta.dy / screenH)
                        .clamp(widget.minSize, widget.maxSize);
                _dssCtrl.jumpTo(newSize);
              },
              onVerticalDragEnd: (_) {
                if (!_dssCtrl.isAttached) return;
                final cur = _dssCtrl.size;
                final snaps = <double>[
                  widget.minSize,
                  ...(effectiveSnaps ?? const []),
                  widget.maxSize,
                ];
                final nearest = snaps.reduce(
                  (a, b) =>
                      (a - cur).abs() < (b - cur).abs() ? a : b,
                );
                _dssCtrl.animateTo(
                  nearest,
                  duration: const Duration(milliseconds: 200),
                  curve: Curves.easeOut,
                );
              },
              child: Container(
                height: 20.0,
                alignment: Alignment.center,
                child: Container(
                  width: 60.0,
                  height: 4.0,
                  decoration: BoxDecoration(
                    color: colors.bg.subtlest,
                    borderRadius: BorderRadius.circular(radius.rd),
                  ),
                ),
              ),
            ),

            // ── White panel ───────────────────────────────────────────────
            Expanded(
              child: Container(
                decoration: BoxDecoration(
                  color: colors.bg.primary,
                  borderRadius: BorderRadius.only(
                    topLeft: Radius.circular(radius.xl),
                    topRight: Radius.circular(radius.xl),
                  ),
                  boxShadow: const [
                    BoxShadow(
                      color: Color(0x26000000),
                      blurRadius: 24,
                      offset: Offset(0, -4),
                    ),
                  ],
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    // ── Header — only rendered when at least one element present
                    if (hasHeader)
                      Padding(
                        padding: EdgeInsets.fromLTRB(16.0, 24.0, 16.0, 16.0),
                        child: Row(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Expanded(
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.start,
                                mainAxisSize: MainAxisSize.min,
                                children: [
                                  if (widget.title != null)
                                    Text(
                                      widget.title!,
                                      style: TextStyle(
                                        fontFamily: BTTypography.fontFamily,
                                        fontSize: 18.0,
                                        fontWeight: FontWeight.w700,
                                        height: 1.4,
                                        color: colors.text.primary,
                                      ),
                                    ),
                                  if (widget.subtext != null) ...[
                                    SizedBox(height: 4.0),
                                    Text(
                                      widget.subtext!,
                                      style: TextStyle(
                                        fontFamily: BTTypography.fontFamily,
                                        fontSize: 14.0,
                                        fontWeight: FontWeight.w500,
                                        height: 1.4,
                                        color: colors.text.secondary,
                                      ),
                                    ),
                                  ],
                                ],
                              ),
                            ),
                            if (widget.hasCloseIcon)
                              GestureDetector(
                                onTap: widget.onClose ??
                                    () => Navigator.of(ctx).pop(),
                                behavior: HitTestBehavior.opaque,
                                child: SizedBox(
                                  width: 24.0,
                                  height: 24.0,
                                  child: Icon(
                                    Icons.close,
                                    size: 16,
                                    color: colors.text.secondary,
                                  ),
                                ),
                              ),
                          ],
                        ),
                      ),

                    // ── Scrollable body ──────────────────────────────────────
                    Expanded(
                      child: widget.contentBuilder != null
                          ? widget.contentBuilder!(
                              ctx,
                              scrollController,
                              _dssCtrl,
                            )
                          : SingleChildScrollView(
                              controller: scrollController,
                              padding:
                                  EdgeInsets.fromLTRB(16.0, 16.0, 16.0, 0),
                              child: widget.content,
                            ),
                    ),

                    // ── Footer — custom widget takes priority over default ────
                    if (widget.footer != null)
                      Padding(
                        padding: EdgeInsets.fromLTRB(16.0, 16.0, 16.0, 16.0),
                        child: widget.footer,
                      )
                    else if (widget.hasFooter)
                      Padding(
                        padding: EdgeInsets.fromLTRB(16.0, 16.0, 16.0, 16.0),
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.stretch,
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            SizedBox(
                              width: double.infinity,
                              child: BTButton(
                                label: widget.primaryLabel,
                                onPressed: widget.onPrimary ??
                                    () => Navigator.of(ctx).pop(),
                              ),
                            ),
                            if (widget.hasSecondaryButton) ...[
                              SizedBox(height: 8.0),
                              SizedBox(
                                width: double.infinity,
                                child: BTButton(
                                  label: widget.secondaryLabel,
                                  variant: BTButtonVariant.secondaryLight,
                                  onPressed: widget.onSecondary ??
                                      () => Navigator.of(ctx).pop(),
                                ),
                              ),
                            ],
                          ],
                        ),
                      ),
                  ],
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}
